const cleanResume = (resume) => resume.replace(/^«\s*|\s*»$/g, "").trim();
const buildLead = (resume) => {
  const cleaned = cleanResume(resume);
  const match = cleaned.match(/.{1,170}?(?:[.!?…]|$)/u)?.[0]?.trim();
  if (match && match.length >= 60) {
    return match;
  }
  return cleaned.length > 180 ? `${cleaned.slice(0, 177).trim()}…` : cleaned;
};
const getSource = (link) => {
  if (!link) {
    return "Retour lectrice";
  }
  if (link.includes("amazon.")) {
    return "Amazon";
  }
  if (link.includes("instagram.com")) {
    return "Instagram";
  }
  return "Lien externe";
};
const getTag = (source) => {
  if (source === "Instagram") {
    return "Post Instagram";
  }
  if (source === "Amazon") {
    return "Avis lecteur";
  }
  return "Retour de lecture";
};
const getAccent = (slug) => slug === "le-coeur-dankaa" ? "#3d3834" : "#3a4d45";
const reviews = rawReviews.map((review) => {
  const source = getSource(review.linktoReview);
  return {
    id: `review-${review.id}`,
    rating: 5,
    text: buildLead(review.resume),
    excerpt: cleanResume(review.resume),
    bookSlug: review.slug,
    book: review.saga,
    date: review.date,
    author: review.author,
    source,
    tag: getTag(source),
    accent: getAccent(review.slug),
    link: review.linktoReview,
    isbn: review.isbn
  };
});

export { reviews as r };
